module RefModule(  
    input clk,  
    input rst,  
    input [3:0] temp,  
    output reg warning  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            warning <= 0;  
        else if (temp > 4'd10)  
            warning <= 1;  
        else  
            warning <= 0;  
    end  
endmodule
